const express = require('express');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const { URL } = require('url');

const app = express();
const PORT = process.env.PORT || 3000;

// Session configuration
app.use(session({
  secret: process.env.SESSION_SECRET || 'your-secret-key-here',
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 24 * 60 * 60 * 1000
  }
}));

// OpenID Connect configuration
const OIDC_CONFIG = {
  issuer: process.env.OIDC_ISSUER || 'https://your-oidc-provider.com',
  clientId: process.env.OIDC_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.OIDC_CLIENT_SECRET || 'your-client-secret',
  redirectUri: process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback'
};

// Validate OIDC issuer
function validateIssuer(issuer) {
  if (!issuer || typeof issuer !== 'string') return false;
  try {
    const url = new URL(issuer);
    return url.protocol === 'https:' && url.hostname;
  } catch (error) {
    return false;
  }
}

// Validate redirect URI
function validateRedirectUri(uri) {
  if (!uri || typeof uri !== 'string') return false;
  try {
    const url = new URL(uri);
    return url.protocol === 'https:' || url.hostname === 'localhost';
  } catch (error) {
    return false;
  }
}

// Validate client ID
function validateClientId(clientId) {
  return clientId && typeof clientId === 'string' && clientId.length > 0;
}

// Validate ID token
function validateIdToken(idToken) {
  if (!idToken || typeof idToken !== 'string') return false;
  try {
    const decoded = jwt.decode(idToken);
    return decoded && decoded.iss && decoded.sub && decoded.exp;
  } catch (error) {
    return false;
  }
}

// Extract claims from ID token
function extractClaims(idToken) {
  try {
    const decoded = jwt.decode(idToken);
    if (!decoded) return null;
    
    // Validate required claims
    if (!decoded.iss || !decoded.sub || !decoded.exp) {
      throw new Error('Invalid token claims');
    }
    
    // Validate issuer
    if (!validateIssuer(decoded.iss)) {
      throw new Error('Invalid issuer');
    }
    
    // Validate expiration
    const now = Math.floor(Date.now() / 1000);
    if (decoded.exp < now) {
      throw new Error('Token expired');
    }
    
    return {
      sub: decoded.sub,
      iss: decoded.iss,
      aud: decoded.aud,
      exp: decoded.exp,
      iat: decoded.iat,
      nonce: decoded.nonce,
      email: decoded.email,
      name: decoded.name,
      preferred_username: decoded.preferred_username,
      given_name: decoded.given_name,
      family_name: decoded.family_name
    };
  } catch (error) {
    console.error('Token validation error:', error.message);
    return null;
  }
}

// Create user session
function createUserSession(req, claims) {
  if (!claims || !claims.sub) return false;
  
  req.session.userId = claims.sub;
  req.session.userClaims = claims;
  req.session.isAuthenticated = true;
  req.session.createdAt = Date.now();
  
  return true;
}

// Middleware to check authentication
function requireAuth(req, res, next) {
  if (req.session && req.session.isAuthenticated) {
    next();
  } else {
    res.redirect('/login');
  }
}

// Login endpoint
app.get('/login', (req, res) => {
  const authUrl = new URL(`${OIDC_CONFIG.issuer}/authorize`);
  authUrl.searchParams.append('response_type', 'code');
  authUrl.searchParams.append('client_id', OIDC_CONFIG.clientId);
  authUrl.searchParams.append('redirect_uri', OIDC_CONFIG.redirectUri);
  authUrl.searchParams.append('scope', 'openid profile email');
  authUrl.searchParams.append('nonce', Math.random().toString(36).substring(2));
  
  res.redirect(authUrl.toString());
});

// Callback endpoint
app.get('/callback', async (req, res) => {
  const { code, state, error } = req.query;
  
  if (error) {
    return res.status(400).send(`Authentication error: ${error}`);
  }
  
  if (!code) {
    return res.status(400).send('Authorization code missing');
  }
  
  try {
    // Exchange authorization code for tokens
    const tokenResponse = await fetch(`${OIDC_CONFIG.issuer}/token`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': `Basic ${Buffer.from(`${OIDC_CONFIG.clientId}:${OIDC_CONFIG.clientSecret}`).toString('base64')}`
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OIDC_CONFIG.redirectUri
      })
    });
    
    const tokenData = await tokenResponse.json();
    
    if (!tokenData.id_token) {
      return res.status(400).send('ID token missing from response');
    }
    
    // Validate and extract claims
    const claims = extractClaims(tokenData.id_token);
    
    if (!claims) {
      return res.status(400).send('Invalid ID token');
    }
    
    // Create session
    if (createUserSession(req, claims)) {
      res.redirect('/dashboard');
    } else {
      res.status(400).send('Failed to create session');
    }
    
  } catch (error) {
    console.error('Authentication error:', error);
    res.status(500).send('Authentication failed');
  }
});

// Dashboard endpoint
app.get('/dashboard', requireAuth, (req, res) => {
  if (!req.session.userClaims) {
    return res.status(401).send('Unauthorized');
  }
  
  res.json({
    message: 'Welcome to your dashboard',
    user: req.session.userClaims
  });
});

// Logout endpoint
app.get('/logout', (req, res) => {
  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
      return res.status(500).send('Logout failed');
    }
    res.redirect('/');
  });
});

// Root endpoint
app.get('/', (req, res) => {
  if (req.session.isAuthenticated) {
    res.redirect('/dashboard');
  } else {
    res.redirect('/login');
  }
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Export for testing
module.exports = {
  validateIssuer,
  validateRedirectUri,
  validateClientId,
  validateIdToken,
  extractClaims,
  createUserSession,
  requireAuth
};